<?php
namespace App\Domain\Inventory\Instances\Refinement;
use App\Domain\Equipment\Data\ItemStatBonuses;use App\Models\RefinementStatModifier;use InvalidArgumentException;
final class ItemRefinementStatCalculator{public function calculate(array $rawBonuses,$level,RefinementStatModifier $modifier=null){$level=(int)$level;if($level<0||$level>RefinementStatModifierLimits::MAX_LEVEL)throw new InvalidArgumentException('Invalid refinement level.');$base=new ItemStatBonuses($rawBonuses['max_health'],$rawBonuses['attack'],$rawBonuses['defense'],$rawBonuses['accuracy'],$rawBonuses['evasion'],$rawBonuses['critical_chance'],$rawBonuses['attack_speed']);$configured=$level===0||$modifier!==null;$points=$level===0?0:($modifier?(int)$modifier->stat_increase_basis_points:0);$integer=[];foreach(['max_health','attack','defense','accuracy','evasion'] as $key)$integer[$key]=$this->increase((int)$rawBonuses[$key],$points);$critical=$this->increase($base->criticalChanceHundredths(),$points);$speed=$this->increase($base->attackSpeedHundredths(),$points);$refinement=new ItemStatBonuses($integer['max_health'],$integer['attack'],$integer['defense'],$integer['accuracy'],$integer['evasion'],ItemStatBonuses::decimalFromHundredths($critical),ItemStatBonuses::decimalFromHundredths($speed));$total=new ItemStatBonuses($this->sum($base->maxHealth(),$refinement->maxHealth()),$this->sum($base->attack(),$refinement->attack()),$this->sum($base->defense(),$refinement->defense()),$this->sum($base->accuracy(),$refinement->accuracy()),$this->sum($base->evasion(),$refinement->evasion()),ItemStatBonuses::decimalFromHundredths($this->sum($base->criticalChanceHundredths(),$critical)),ItemStatBonuses::decimalFromHundredths($this->sum($base->attackSpeedHundredths(),$speed)));return new ItemRefinementStatBreakdown($base,$refinement,$total,$level,$configured?$points:null,$configured);}private function increase($base,$points){if(!is_int($base)||$base<0||!is_int($points)||$points<0||$points>RefinementStatModifierLimits::MAX_BASIS_POINTS)throw new InvalidArgumentException('Invalid refinement stat operands.');if($base>0&&$points>intdiv(PHP_INT_MAX,$base))throw new InvalidArgumentException('Refinement stat multiplication overflow.');return intdiv($base*$points,10000);}private function sum($left,$right){if($right>PHP_INT_MAX-$left)throw new InvalidArgumentException('Refinement stat addition overflow.');return$left+$right;}}
